import { Link, useNavigate } from "react-router-dom";

export default function Login() {
  const navigate = useNavigate();

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-600 via-purple-600 to-pink-500 px-4">

      <div className="w-full max-w-md bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl p-8">

        <h1 className="text-white text-3xl font-bold text-center">
          Login
        </h1>

        <input className="w-full mt-6 p-3 rounded-lg bg-white/20 text-white placeholder-white outline-none" placeholder="Email" />
        <input className="w-full mt-4 p-3 rounded-lg bg-white/20 text-white placeholder-white outline-none" placeholder="Password" />

        <button
          onClick={() => navigate("/feed")}
          className="w-full mt-6 bg-white text-black py-3 rounded-lg font-semibold hover:bg-gray-200 transition"
        >
          Login
        </button>

        <p className="text-center text-white/70 text-sm mt-5">
          Don’t have an account?{" "}
          <Link to="/register" className="text-white font-semibold underline">
            Register
          </Link>
        </p>

      </div>
    </div>
  );
}
